const repo = $input.first().json.gh_repo;
const keywords = $input.first().json.keywords;
const date = new Date();
date.setDate(date.getDate() - 180);
const dateString = date.toISOString().split('T')[0];
const chunks = [];
for (let i = 0; i < keywords.length; i += 5) {
  chunks.push(keywords.slice(i, i + 5));
}
return chunks.map(chunk => ({
  query: `repo:${repo} type:pr created:>${dateString} in:title (${chunk.join(' OR ')})`,
  repo_owner: repo.split('/')[0],
  repo_name: repo.split('/')[1]
}));

const all_responses = $input.all();
const pr_numbers = [];
const prs = [];
const seen = new Set();

for (const response of all_responses) {
  const items = response.json.items || [];
  for (const item of items) {
    const title = item.title || "";
    if (title.toLowerCase().includes("[backport")) continue;

    // Determine state
    const isMerged = !!(item.pull_request && item.pull_request.merged_at);
    const state = isMerged ? 'merged' : item.state;

    // Track number and state to detect state changes
    const key = `${item.number}:${state}`;

    if (!seen.has(item.number)) {
      seen.add(item.number);
      pr_numbers.push(key);
      prs.push(item);
    }
  }
}
return {
  pr_numbers: pr_numbers,
  prs: prs
};

const all_items = $input.all();
const cached_item = all_items[0]?.json?.data?.[0] || {};
const cur = all_items[1]?.json || {};

const pr_numbers_prev_raw = cached_item.pr_numbers || [];
const pr_numbers_prev = pr_numbers_prev_raw.map(x => x.toString().includes(':') ? x : `${x}:open`);
const pr_numbers_cur = cur.pr_numbers || [];

const pr_numbers_diff = pr_numbers_cur.filter(x => !pr_numbers_prev.includes(x));
const diff_numbers = pr_numbers_diff.map(x => parseInt(x.split(':')[0]));

const isManual = $execution.mode === 'manual' || $execution.mode === 'test';
const new_prs_data = isManual 
  ? (cur.prs || []) 
  : (cur.prs || []).filter(x => diff_numbers.includes(x.number));

return {
  pr_numbers: { prev: pr_numbers_prev, cur: pr_numbers_cur, diff: pr_numbers_diff },
  prs: new_prs_data,
  isManual: isManual,
  cache_payload: { pr_numbers: pr_numbers_cur, prs: cur.prs || [] }
};

const item = $input.first().json;
const new_prs = item.prs || [];
if (new_prs.length === 0) return [];

const keywords = $node["Config"].json.keywords || [];
const workflowId = $workflow.id;
const workflowName = $workflow.name;
const executionId = $execution.id;

const escapeHtml = (unsafe) => (unsafe || "").toString().replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#039;");
const formatDate = (isoString) => {
  if (!isoString) return "N/A";
  const d = new Date(isoString);
  const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
  return `${months[d.getMonth()]} ${d.getDate()}`;
};

const IMG_PR_OPEN = 'https://img.shields.io/static/v1.png?label=&message=%20&color=238636&logo=git-pull-request&logoColor=white&style=flat-square';
const IMG_PR_MERGED = 'https://img.shields.io/static/v1.png?label=&message=%20&color=8957e5&logo=git-merge&logoColor=white&style=flat-square';
const IMG_PR_CLOSED = 'https://img.shields.io/static/v1.png?label=&message=%20&color=cf222e&logo=git-pull-request&logoColor=white&style=flat-square';

const groupedPrs = {};
for (const kw of keywords) groupedPrs[kw] = [];
for (const pr of new_prs) {
  const titleLower = pr.title.toLowerCase();
  for (const kw of keywords) if (titleLower.includes(kw.toLowerCase())) groupedPrs[kw].push(pr);
}

for (const kw of keywords) {
  groupedPrs[kw].sort((a, b) => {
    const aMerged = !!(a.pull_request && a.pull_request.merged_at);
    const bMerged = !!(b.pull_request && b.pull_request.merged_at);
    const aClosed = a.state === 'closed' && !aMerged;
    const bClosed = b.state === 'closed' && !bMerged;
    const aScore = aMerged ? 0 : (aClosed ? 2 : 1);
    const bScore = bMerged ? 0 : (bClosed ? 2 : 1);
    if (aScore !== bScore) return aScore - bScore;
    const aDate = new Date(aMerged ? a.pull_request.merged_at : (aClosed ? a.closed_at : a.created_at));
    const bDate = new Date(bMerged ? b.pull_request.merged_at : (bClosed ? b.closed_at : b.created_at));
    return bDate - aDate;
  });
}

let html_body = `<!DOCTYPE html><html><head><meta name="viewport" content="width=device-width, initial-scale=1.0"><style>
body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif; line-height: 1.5; color: #24292f; background-color: #f6f8fa; margin: 0; padding: 10px; }
