.keyword-title-link:hover { color: #0969da; border-bottom-color: #0969da; }
.pr-item { padding-bottom: 16px; margin-bottom: 16px; border-bottom: 1px dashed #d0d7de; display: table; width: 100%; border-collapse: collapse; }
.pr-item:last-child { border-bottom: none; margin-bottom: 0; padding-bottom: 0; }
