.pr-main-cell { display: table-cell; vertical-align: top; min-width: 0; }
.pr-title { font-size: 16px; font-weight: 600; color: #0969da; text-decoration: none; display: block; margin-bottom: 2px; word-break: break-word; }
.pr-title:hover { text-decoration: underline; }
