.avatar { border-radius: 50%; vertical-align: middle; margin: 0 4px; }
.author-link { color: inherit; text-decoration: none; font-weight: 600; }
.author-link:hover { text-decoration: underline; color: #0969da; }
.footer { padding: 16px 20px; background-color: #f6f8fa; border-top: 1px solid #d0d7de; font-size: 12px; color: #57606a; }
.keywords { margin-top: 8px; margin-bottom: 16px; }
.keyword-tag { background-color: #ddf4ff; color: #0969da; padding: 2px 8px; border-radius: 12px; font-weight: 500; display: inline-block; margin: 2px; text-decoration: none; font-size: 11px; }
.keyword-tag:hover { background-color: #0969da; color: #ffffff; }
