</style></head><body><div class="container"><div class="header"><h1>📮 GitHub nixpkgs PR Digest</h1></div><div class="content">`;

for (const kw of keywords) {
  const prs = groupedPrs[kw];
  if (prs.length === 0) continue;
  const searchUrl = `https://github.com/NixOS/nixpkgs/pulls?q=is%3Aopen+created:>${new Date(Date.now() - 180 * 86400000).toISOString().split('T')[0]}+in:title%20${encodeURIComponent(kw)}`;
  html_body += `<div class="keyword-section"><a href="${searchUrl}" class="keyword-title-link">🔖 ${escapeHtml(kw)} (${prs.length})</a>`;
  for (const pr of prs) {
    const title = escapeHtml(pr.title);
    const url = pr.html_url || "#";
    const number = pr.number;
    const user = pr.user?.login || "unknown";
    const userAvatar = pr.user?.avatar_url || "";
    const userUrl = pr.user?.html_url || "#";
    const isMerged = !!(pr.pull_request && pr.pull_request.merged_at);
    const isClosed = pr.state === 'closed' && !isMerged;
    let actionText = 'opened';
    let iconUrl = IMG_PR_OPEN;
    let statusAlt = 'Open';
    let dateStr = formatDate(pr.created_at);
    if (isMerged) {
      actionText = 'merged';
      iconUrl = IMG_PR_MERGED;
      statusAlt = 'Merged';
      dateStr = formatDate(pr.pull_request.merged_at);
    } else if (isClosed) {
      actionText = 'closed';
      iconUrl = IMG_PR_CLOSED;
      statusAlt = 'Closed';
      dateStr = formatDate(pr.closed_at);
    }
    const statusImg = `<img src="${iconUrl}" height="20" border="0" style="display:block; border:0; height:20px; border-radius: 2px;" alt="${statusAlt}">`;
    html_body += `<div class="pr-item"><div class="status-icon-cell">${statusImg}</div><div class="pr-main-cell"><a href="${url}" class="pr-title">${title}</a><div class="pr-meta">#${number} by <a href="${userUrl}" class="author-link"><img src="${userAvatar}" width="14" height="14" class="avatar" alt="" border="0" style="border-radius:50%;">${user}</a> ${actionText} on ${dateStr}</div></div></div>`;
  }
  html_body += `</div>`;
}

html_body += `</div><div class="footer"><div style="font-weight: 600; margin-bottom: 4px;">Active Keywords:</div><div class="keywords">`;
for (const kw of keywords) {
  const tagSearchUrl = `https://github.com/NixOS/nixpkgs/pulls?q=is%3Aopen+created:>${new Date(Date.now() - 180 * 86400000).toISOString().split('T')[0]}+in:title%20${encodeURIComponent(kw)}`;
  html_body += `<a href="${tagSearchUrl}" class="keyword-tag">${escapeHtml(kw)}</a>`;
}
html_body += `</div><div class="debug-links"><div style="margin-bottom: 8px; font-weight: 600; color: #24292f;">${escapeHtml(workflowName)}</div><a href="https://n8n.brkn.lol/workflow/${workflowId}">📝 Edit Workflow</a><a href="https://n8n.brkn.lol/workflow/${workflowId}/executions/${executionId}">🔍 View Execution</a></div><p style="margin-top: 16px; font-style: italic; opacity: 0.8;">Automated digest from n8n.brkn.lol</p></div></div></body></html>`;

return { emailBodyHtml: html_body, emailBodyText: "PR Digest updated with merged/closed distinction." };

